9	CUTE_DEVICE
10	void tma_gather4(const void* desc_ptr, transac_bar_t &mbar_ptr, void* smem_ptr, int col_idx, int4 row_idxs, int64_t cache_hint) {
11	    uint32_t smem_addr = cute::cast_smem_ptr_to_uint(smem_ptr);
12	    uint32_t mbar_addr = cute::cast_smem_ptr_to_uint(&mbar_ptr);
13	    asm volatile(
14	        "cp.async.bulk.tensor.2d.shared::cta.global.tile::gather4.mbarrier::complete_tx::bytes.cta_group::1.L2::cache_hint [%0], [%1, {%2, %3, %4, %5, %6}], [%7], %8;\n"
15	        :
16	        : "r"(smem_addr), "l"(desc_ptr), "r"(col_idx), 
17	          "r"(row_idxs.x), "r"(row_idxs.y), "r"(row_idxs.z), "r"(row_idxs.w), 
18	          "r"(mbar_addr), "l"(cache_hint)
19	        : "memory"
20	    );
21	}
