68	CUTE_DEVICE
69	float2 float2_mul(const float2 &a, const float2 &b) {
70	    float2 c;
71	    asm volatile(
72	        "mul.f32x2 %0, %1, %2;\n"
73	        : "=l"(reinterpret_cast<uint64_t&>(c))
74	        : "l"(reinterpret_cast<uint64_t const&>(a)),
75	          "l"(reinterpret_cast<uint64_t const&>(b)));
76	    return c;
