135	CUTE_DEVICE
136	void issue_clc_query_multicast_cluster_all(transac_bar_t &bar, CLCResponseObj &response_obj) {
137	    uint32_t response_addr = cute::cast_smem_ptr_to_uint(response_obj.opaque);
138	    uint32_t mbarrier_addr = cute::cast_smem_ptr_to_uint(&bar);
139	    asm volatile(
