177	// LDG.256 or LDG.256 with non-coherent cache (https://docs.nvidia.com/cuda/parallel-thread-execution/#data-movement-and-conversion-instructions-ld)
178	// We use macro instead of function here, since we need a multi-level recursive dispatch based on template parameters if using function
179	// NC_STR should be either "" or ".nc"
180	// L1_CACHE_HINT_STR should be either "evict_first", "evict_normal", "evict_last", "evict_unchanged", or "no_allocate"
181	// L2_CACHE_HINT_STR should be either "evict_first", "evict_normal", or "evict_last"
182	// L2_PREFETCH_SIZE_STR should be either "64B", "128B", or "256B"
183	#define KU_LDG_256(global_addr, result, NC_STR, L1_CACHE_HINT_STR, L2_CACHE_HINT_STR, L2_PREFETCH_SIZE_STR) \
184	    { \
185	        static_assert(std::is_pointer_v<decltype(global_addr)> || std::is_array_v<decltype(global_addr)>, "`global_addr` must be a pointer"); \
186	        static_assert(std::is_pointer_v<decltype(result)> || std::is_array_v<decltype(result)>, "`result` must be a pointer"); \
187	        uint64_t* result_as_uint64_ptr = (uint64_t*)(result); \
188	        asm volatile( \
189	            "ld.global" NC_STR ".L1::" L1_CACHE_HINT_STR ".L2::" L2_CACHE_HINT_STR ".L2::" L2_PREFETCH_SIZE_STR ".v4.u64 {%0, %1, %2, %3}, [%4];\n" \
190	            : "=l"(result_as_uint64_ptr[0]), "=l"(result_as_uint64_ptr[1]), \
191	            "=l"(result_as_uint64_ptr[2]), "=l"(result_as_uint64_ptr[3]) \
192	            : "l"(global_addr) \
193	        ); \
194	    }
195	
196	// STG.256 (https://docs.nvidia.com/cuda/parallel-thread-execution/#data-movement-and-conversion-instructions-st)
197	// L1_CACHE_HINT_STR should be either "evict_first", "evict_normal", "evict_last", "evict_unchanged", or "no_allocate"
198	// L2_CACHE_HINT_STR should be either "evict_first", "evict_normal", or "evict_last"
199	#define KU_STG_256(global_addr, src, L1_CACHE_HINT_STR, L2_CACHE_HINT_STR) \
200	    { \
201	        static_assert(std::is_pointer_v<decltype(global_addr)> || std::is_array_v<decltype(global_addr)>, "`global_addr` must be a pointer"); \
202	        static_assert(std::is_pointer_v<decltype(src)> || std::is_array_v<decltype(src)>, "`src` must be a pointer"); \
203	        uint64_t const* src_as_uint64_ptr = (uint64_t const*)(src); \
204	        asm volatile( \
205	            "st.global.L1::" L1_CACHE_HINT_STR ".L2::" L2_CACHE_HINT_STR ".v4.u64 [%0], {%1, %2, %3, %4};\n" \
206	            : \
207	            : "l"(global_addr), "l"(src_as_uint64_ptr[0]), "l"(src_as_uint64_ptr[1]), \
208	            "l"(src_as_uint64_ptr[2]), "l"(src_as_uint64_ptr[3]) \
209	        ); \
210	    }
211	
212	}
