330	__device__ __forceinline__
331	void tmem_ld_16dp256bNx(uint32_t tmem_start, void* data_) {
332	    uint32_t* data = (uint32_t*)data_;
333	    static_assert(kNumReplications == 1 || kNumReplications == 2 || kNumReplications == 4 || kNumReplications == 8 || kNumReplications == 16 || kNumReplications == 32, "Invalid kNumReplications");
334	#ifndef __VSCODE_IDE__
335	    [&]<size_t... Is>(cute::index_sequence<Is...>) {
336	        if constexpr (kNumReplications == 1) {
337	            cute::SM100_TMEM_LOAD_16dp256b1x::copy(tmem_start, data[Is]...);
338	        } else if constexpr (kNumReplications == 2) {
