7	// cp.async.cg (cache global) with prefetch and predicate (https://docs.nvidia.com/cuda/parallel-thread-execution/#data-movement-and-conversion-instructions-cp-async)
8	template<PrefetchSize PREFETCH_SIZE=PrefetchSize::B128>
9	CUTE_DEVICE
10	void cp_async_cacheglobal(const void* src, void* dst, bool pred=true) {
11	    uint32_t dst_addr = cute::cast_smem_ptr_to_uint(dst);
12	    if constexpr (PREFETCH_SIZE == PrefetchSize::B64) {
13	        asm volatile("cp.async.cg.shared.global.L2::64B [%0], [%1], 16, %2;\n"
14	            :: "r"(dst_addr),
15	               "l"(src),
16	               "r"(pred?16:0));
17	    } else if constexpr (PREFETCH_SIZE == PrefetchSize::B128) {
18	        asm volatile("cp.async.cg.shared.global.L2::128B [%0], [%1], 16, %2;\n"
19	            :: "r"(dst_addr),
20	               "l"(src),
21	               "r"(pred?16:0));
22	    } else if constexpr (PREFETCH_SIZE == PrefetchSize::B256) {
23	        asm volatile("cp.async.cg.shared.global.L2::256B [%0], [%1], 16, %2;\n"
24	            :: "r"(dst_addr),
25	               "l"(src),
26	               "r"(pred?16:0));
27	    } else {
28	        static_assert(PREFETCH_SIZE == PrefetchSize::B64 ||
29	                      PREFETCH_SIZE == PrefetchSize::B128 ||
30	                      PREFETCH_SIZE == PrefetchSize::B256,
31	                      "Unsupported prefetch size for cp_async_cacheglobal.");
32	    }
33	}
34	
35	// Create fraction-based cache policy (https://docs.nvidia.com/cuda/parallel-thread-execution/#data-movement-and-conversion-instructions-createpolicy)
36	template<CacheHint PRIMARY_PRIORITY, CacheHint SECONDARY_PRIORITY>
37	CUTE_DEVICE
38	int64_t create_fraction_based_cache_policy(float fraction = 1.0f) {
39	    int64_t result;
40	    #define EMIT(PRIMARY_PRIORITY_STR, SECONDARY_PRIORITY_STR) \
41	        asm volatile( \
42	            "createpolicy.fractional.L2::" PRIMARY_PRIORITY_STR ".L2::" SECONDARY_PRIORITY_STR ".b64 %0, %1;\n" \
43	            : "=l"(result) \
44	            : "f"(fraction) \
45	        );
46	    #define EMIT2(PRIMARY_PRIORITY_STR) \
47	        { \
48	            if constexpr (SECONDARY_PRIORITY == CacheHint::EVICT_FIRST) { \
49	                EMIT(PRIMARY_PRIORITY_STR, "evict_first") \
50	            } else if constexpr (SECONDARY_PRIORITY == CacheHint::EVICT_UNCHANGED) { \
51	                EMIT(PRIMARY_PRIORITY_STR, "evict_unchanged") \
52	            } else { \
53	                static_assert(SECONDARY_PRIORITY == CacheHint::EVICT_FIRST || \
54	                            SECONDARY_PRIORITY == CacheHint::EVICT_UNCHANGED, \
55	                            "Unsupported secondary cache hint for create_fraction_based_cache_policy."); \
56	            } \
57	        }
58	    if constexpr (PRIMARY_PRIORITY == CacheHint::EVICT_FIRST) {
59	        EMIT2("evict_first");
60	    } else if constexpr (PRIMARY_PRIORITY == CacheHint::EVICT_NORMAL) {
61	        EMIT2("evict_normal");
62	    } else if constexpr (PRIMARY_PRIORITY == CacheHint::EVICT_LAST) {
63	        EMIT2("evict_last");
64	    } else if constexpr (PRIMARY_PRIORITY == CacheHint::EVICT_UNCHANGED) {
65	        EMIT2("evict_unchanged");
66	    } else {
67	        static_assert(PRIMARY_PRIORITY == CacheHint::EVICT_FIRST ||
68	                      PRIMARY_PRIORITY == CacheHint::EVICT_NORMAL ||
69	                      PRIMARY_PRIORITY == CacheHint::EVICT_LAST ||
70	                      PRIMARY_PRIORITY == CacheHint::EVICT_UNCHANGED,
71	                      "Unsupported primary cache hint for create_fraction_based_cache_policy.");
72	    }
73	    #undef EMIT
74	    #undef EMIT2
75	    return result;
76	}
77	
78	// Create a simple cache policy (equivalent to create_fraction_based_cache_policy(1.0f))
79	// The same as cute::TMA::CacheHintSmXX
80	template<CacheHint CACHE_HINT>
81	CUTE_DEVICE
82	constexpr int64_t create_simple_cache_policy() {
83	    if constexpr (CACHE_HINT == CacheHint::EVICT_FIRST) {
84	        return 0x12F0000000000000;  // Result of createpolicy.fractional.L2::evict_first.b64
85	    } else if constexpr (CACHE_HINT == CacheHint::EVICT_NORMAL) {
86	        return 0x1000000000000000;  // Copied from CuTe. Unsure about the exact meaning. (TODO Change to 0x16F0000000000000?)
87	    } else if constexpr (CACHE_HINT == CacheHint::EVICT_LAST) {
88	        return 0x14F0000000000000;  // Result of createpolicy.fractional.L2::evict_last.b64
89	    } else {
90	        static_assert(CACHE_HINT == CacheHint::EVICT_FIRST ||
91	                      CACHE_HINT == CacheHint::EVICT_NORMAL ||
92	                      CACHE_HINT == CacheHint::EVICT_LAST,
93	                      "Unsupported cache hint for create_simple_cache_policy.");
94	    }
95	}
96	
97	// AtomicAdd (https://docs.nvidia.com/cuda/parallel-thread-execution/#parallel-synchronization-and-communication-instructions-red)
98	CUTE_DEVICE
99	void atomicadd_f32_with_policy_and_pred(void* global_addr, const float &data, int64_t cache_policy, uint32_t pred = true) {
100	    asm volatile(
101	        "{\n\t"
102	        ".reg .pred p;\n\t"
103	        "setp.eq.u32 p, %3, 1;\n\t"
104	        "@p red.relaxed.gpu.global.add.L2::cache_hint.f32 [%1], %0, %2; \n\t"
105	        "}"
106	        : 
107	        : "f"(data),
108	          "l"((int64_t)global_addr), "l"(cache_policy), "r"(pred)
109	    );
110	}
111	
112	// Get the id of the current SM
113	// About %smid (https://docs.nvidia.com/cuda/parallel-thread-execution/#special-registers-smid): PTX document says that %smid ranges from 0 to %nsmid-1, while "The SM identifier numbering is not guaranteed to be contiguous, so %nsmid may be larger than the physical number of SMs in the device.". However, result shows that, at least for sm90 and sm100f, %nsmid is the number of physical SMs - 1. For the sake of safety, I recommend you to check the return of get_sm_id manually or call `get_sm_id_with_range_check()` defined in `device/sm80/helpers.cuh`.
114	// Besides, PTX document also says that this number may change due to preemption, but currently this never happens according to [DATEN GELÖSCHT]
115	CUTE_DEVICE
116	uint32_t get_sm_id() {
117	    uint32_t ret;
118	    asm volatile("mov.u32 %0, %%smid;\n" : "=r"(ret));
119	    return ret;
120	}
121	
122	// trap (https://docs.nvidia.com/cuda/parallel-thread-execution/#miscellaneous-instructions-trap)
123	CUTE_DEVICE
124	void trap() {
125	    asm volatile("trap;\n");
126	}
127	
128	// LDG.128 or LDG.128 with non-coherent cache (https://docs.nvidia.com/cuda/parallel-thread-execution/#data-movement-and-conversion-instructions-ld)
129	// We use macro instead of function here, since we need a multi-level recursive dispatch based on template parameters if using function
130	// NC_STR should be either "" or ".nc"
131	// L1_CACHE_HINT_STR should be either "evict_first", "evict_normal", "evict_last", "evict_unchanged", or "no_allocate"
132	// L2_PREFETCH_SIZE_STR should be either "64B", "128B", or "256B"
133	// L2 cache hint is not supported since it's only supported for LDG.256
134	#define KU_LDG_128(global_addr, result, NC_STR, L1_CACHE_HINT_STR, L2_PREFETCH_SIZE_STR) \
135	    { \
136	        static_assert(std::is_pointer_v<decltype(global_addr)> || std::is_array_v<decltype(global_addr)>, "`global_addr` must be a pointer"); \
137	        static_assert(std::is_pointer_v<decltype(result)> || std::is_array_v<decltype(result)>, "`result` must be a pointer"); \
138	        uint64_t* result_as_uint64_ptr = (uint64_t*)(result); \
139	        asm volatile( \
140	            "ld.global" NC_STR ".L1::" L1_CACHE_HINT_STR ".L2::" L2_PREFETCH_SIZE_STR ".v2.u64 {%0, %1}, [%2];\n" \
141	            : "=l"(result_as_uint64_ptr[0]), "=l"(result_as_uint64_ptr[1]) \
142	            : "l"(global_addr) \
143	        ); \
144	    }
145	
146	}
