13	>
14	CUTE_DEVICE
15	void launch_tma_copy(
16	    const TMA &tma_copy,
17	    Tensor0 src,
18	    Tensor1 dst,
19	    transac_bar_t &bar,
20	    const cute::TMA::CacheHintSm90 &cache_hint = cute::TMA::CacheHintSm90::EVICT_NORMAL
21	) {
22	    auto thr_tma = tma_copy.get_slice(cute::_0{});
23	    cute::copy(
24	        tma_copy.with(reinterpret_cast<typename transac_bar_t::ValueType&>(bar), 0, cache_hint),
25	        thr_tma.partition_S(src),
26	        thr_tma.partition_D(dst)
27	    );
28	}
