30	// In the layout of fragment A and fragment C during WGMMA, data each thread holds resides in two particular rows. This function converts the local_row_idx (0~2) to the actual row_idx
31	// You may refer to this link for the detailed layout: https://docs.nvidia.com/cuda/parallel-thread-execution/#wgmma-64n16-a
32	CUTE_DEVICE
33	int get_AorC_row_idx(int local_row_idx, int idx_in_warpgroup) {
34	    int row_idx = (idx_in_warpgroup/32)*16 + local_row_idx*8 + (idx_in_warpgroup%32/4);
35	    return row_idx;
36	}
37	
38	// In the layout of fragment A and fragment C during WGMMA, data each thread holds resides in some rows. This function converts the local_elem_idx to the actual col_idx
39	// You may refer to this link for the detailed layout: https://docs.nvidia.com/cuda/parallel-thread-execution/#wgmma-64n16-a
40	CUTE_DEVICE
41	int get_AorC_col_idx(int local_elem_idx, int idx_in_warpgroup) {
42	    int col_idx = 8*(local_elem_idx/4) + (idx_in_warpgroup%4)*2 + (local_elem_idx&1);
43	    return col_idx;
44	}
45	
46	template <bool commit=true, typename Tensor0, typename Tensor1, typename Tensor2, typename TiledMma>
47	CUTE_DEVICE
48	void wgmma(TiledMma &tiled_mma, Tensor0 const &tCrA, Tensor1 const &tCrB, Tensor2 &tCrC, bool zero_init) {
49	    using namespace cute;
50	    constexpr bool Is_RS = !cute::is_base_of<cute::GMMA::DescriptorIterator, typename TiledMma::FrgTypeA>::value;
51	    // Need to cast away const on tCrA since warpgroup_fence_operand doesn't take const
52	    if constexpr (Is_RS) { cute::warpgroup_fence_operand(const_cast<Tensor0 &>(tCrA)); }
53	    warpgroup_fence_operand(tCrC);
54	    warpgroup_arrive();
55	    tiled_mma.accumulate_ = zero_init ? GMMA::ScaleOut::Zero : GMMA::ScaleOut::One;
56	    // Unroll the K mode manually to set scale D to 1
57	    CUTLASS_PRAGMA_UNROLL
58	    for (int k_block = 0; k_block < size<2>(tCrA); ++k_block) {
59	        cute::gemm(tiled_mma, tCrA(_,_,k_block), tCrB(_,_,k_block), tCrC);
60	        tiled_mma.accumulate_ = GMMA::ScaleOut::One;
61	    }
62	    if constexpr (commit) {
63	        warpgroup_commit_batch();
64	    }
65	    warpgroup_fence_operand(tCrC);
66	    if constexpr (Is_RS) { warpgroup_fence_operand(const_cast<Tensor0 &>(tCrA)); }
67	}
68	
69	template <typename Tensor0, typename Tensor1, typename Tensor2, typename TiledMma>
70	CUTE_DEVICE
71	void wgmma_ss(bool clear_accum, TiledMma tiled_mma, Tensor0 const &sA, Tensor1 const &sB, Tensor2 &rC_frag, int idx_in_warpgroup) {
72	    using namespace cute;
73	    ThrMMA thr_mma = tiled_mma.get_slice(idx_in_warpgroup);
74	    Tensor sA_frag = thr_mma.partition_fragment_A(sA);
75	    Tensor sB_frag = thr_mma.partition_fragment_B(sB);
76	    static_assert(size<2>(sA_frag) == size<2>(sB_frag));
77	
78	    warpgroup_fence_operand(rC_frag);
79	    warpgroup_arrive();
80	    tiled_mma.accumulate_ = clear_accum ? GMMA::ScaleOut::Zero : GMMA::ScaleOut::One;
81	    CUTLASS_PRAGMA_UNROLL
82	    for (int k = 0; k < size<2>(sA_frag); ++k) {
83	        cute::gemm(tiled_mma, sA_frag(_, _, k), sB_frag(_, _, k), rC_frag);
84	        tiled_mma.accumulate_ = GMMA::ScaleOut::One;
85	    }
86	    warpgroup_fence_operand(rC_frag);
87	}
88	
